pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    out = ""
    for i in range(0, length(chars)) {
        out = join([out, get(chars, length(chars) - 1 - i)], "")
    }
    return out
}
pure fn is_palindrome(s: Text) -> Boolean {
    return lower(s) == reverse_text(lower(s))
}
entry main(x: Text) { if is_palindrome("racecar") { return "yes" } return "no" }

